<?php include 'header.php';
if(($_GET['action'] ?? '')==='add' && $_SERVER['REQUEST_METHOD']==='POST'){ $id=(int)$_POST['id'];$qty=max(1,(int)$_POST['qty']);$_SESSION['cart'][$id]=($_SESSION['cart'][$id]??0)+$qty;header('Location: cart.php');exit; }
if(($_GET['action'] ?? '')==='remove'){ unset($_SESSION['cart'][(int)$_GET['id']]);header('Location: cart.php');exit; }
$items=[];$total=0;if(!empty($_SESSION['cart'])){$ids=array_keys($_SESSION['cart']);$in=str_repeat('?,',count($ids)-1).'?';$st=$pdo->prepare("SELECT * FROM products WHERE id IN ($in)");$st->execute($ids);$items=$st->fetchAll();foreach($items as $it){$total += product_price($it)*$_SESSION['cart'][$it['id']];}}
?>
<main class="container"><div class="section-title"><h2>Giỏ hàng</h2></div><?php if(!$items): ?><p>Giỏ hàng đang trống.</p><a class="btn" href="products.php">Mua sắm ngay</a><?php else: ?><table><tr><th>Sản phẩm</th><th>Giá</th><th>Số lượng</th><th>Tổng</th><th></th></tr><?php foreach($items as $it): $q=$_SESSION['cart'][$it['id']]; ?><tr><td><img class="cart-img" src="<?=$it['image']?>"> <?=$it['name']?></td><td><?=money(product_price($it))?></td><td><?=$q?></td><td><?=money(product_price($it)*$q)?></td><td><a href="cart.php?action=remove&id=<?=$it['id']?>">Xóa</a></td></tr><?php endforeach; ?></table><h2>Tổng tiền: <?=money($total)?></h2><a class="btn" href="checkout.php">Thanh toán</a><?php endif; ?></main><?php include 'footer.php'; ?>
